#include<bits/stdc++.h>
using namespace std;
int a[300010],f[61][300010];
int main()
{
    int n;
    scanf("%d",&n);
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        f[a[i]][i]=i+1;
        ans=max(ans,a[i]);
    }
    for(int i=1;i<=60;i++)
    {
        for(int j=1;j<=n;j++)
        {
            if(f[i][j])
            {
                continue;
            }
            f[i][j]=f[i-1][f[i-1][j]];
            if(f[i][j])
            {
                ans=max(ans,i);
            }
        }
    }
    printf("%d",ans);
    return 0;
}
